817	\begin{definition}[Cover-totality source-object identification, iter-031]
818	  \label{def:Scheme_HModule_prime_top_sourceIso}
819	  \lean{AlgebraicGeometry.Scheme.HModule'_top_sourceIso}
820	  \uses{def:Scheme_HModule_prime}
821	  Let $k$ be a field, $C$ a category with morphism universe $u$, $J : \GrothendieckTopology\,C$, $T : C$ a terminal object (witnessed by $h_T : \mathtt{IsTerminal}\,T$), and assume $\HasWeakSheafify\,J\,(\Type\,u)$ and $\HasSheafify\,J\,(\ModuleCat.\{u\}\,k)$. There is a natural isomorphism in $\Sheaf\,J\,(\ModuleCat.\{u\}\,k)$:
822	  \[
823	    (\presheafToSheaf\,J\,\_).\mathrm{obj}\,
824	        ((\yoneda \circ (\Functor.\mathtt{whiskeringRight}\,\_\,\_\,\_).\mathrm{obj}\,(\ModuleCat.\mathtt{free}\,k)).\mathrm{obj}\,T)
825	      \;\cong\;
826	      (\constantSheaf\,J\,(\ModuleCat.\{u\}\,k)).\mathrm{obj}\,(\ModuleCat.\mathrm{of}\,k\,k).
827	  \]
828	\end{definition}
