830	\begin{proof}
831	  \leanok
832	  Compose three Mathlib pieces, using the identity $\constantSheaf\,J\,D = \Functor.\mathtt{const}\,C^{\op} \circ \presheafToSheaf\,J\,D$ (\texttt{Mathlib/CategoryTheory/Sites/ConstantSheaf.lean}, line 65):
833	  \begin{enumerate}
834	    \item $\yoneda.\mathrm{obj}\,T \cong (\Functor.\mathtt{const}\,C^{\op}).\mathrm{obj}\,\PUnit$ — the terminal-collapse: at object $X^{\op}$ both presheaves evaluate to a one-element type, with the iso supplied component-wise via $\mathtt{IsTerminal.from}$ for the inverse and $\mathtt{IsTerminal.hom\_ext}$ for the section identity.
835	    \item Whisker right with $(\Functor.\mathtt{whiskeringRight}\,\_\,\_\,\_).\mathrm{obj}\,(\ModuleCat.\mathtt{free}\,k)$, then apply $\Functor.\mathtt{constComp}$ to obtain $((\Functor.\mathtt{const}\,C^{\op}).\mathrm{obj}\,\PUnit) \circ \ModuleCat.\mathtt{free}\,k = (\Functor.\mathtt{const}\,C^{\op}).\mathrm{obj}\,((\ModuleCat.\mathtt{free}\,k).\mathrm{obj}\,\PUnit)$ as an iso.
836	    \item Apply $(\Functor.\mathtt{const}\,C^{\op}).\mathtt{mapIso}$ to the linear-equivalence-derived iso $(\ModuleCat.\mathtt{free}\,k).\mathrm{obj}\,\PUnit \cong \ModuleCat.\mathrm{of}\,k\,k$ (via $\mathtt{Finsupp.LinearEquiv.finsuppUnique}\,k\,k\,\PUnit$ followed by $\mathtt{LinearEquiv.toModuleIso}$).
837	  \end{enumerate}
838	  Apply $(\presheafToSheaf\,J\,\_).\mathtt{mapIso}$ to the composed presheaf-level iso to land in $\Sheaf\,J\,(\ModuleCat.\{u\}\,k)$; the right-hand side then unfolds via the $\constantSheaf$ identity above.
839	\end{proof}
